  ('dietitian-moex-09772', 'dietitian', 'dietitian-moex-096-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '對type 1糖尿病患生病時之措施，以下何者較適當？', '["若食物攝取減少應降低insulin劑量，以預防低血糖", "可採少量多餐含醣類之流質，以預防低血糖", "若未進食，則不必注射insulin", "若有發燒則應禁食，但以靜脈補充水分"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:54+00:00", "source_pdf_sha1": "a06c8ec0af96", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "112", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 23, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
